import React, { useState } from "react";
import style from "./Header.module.css";
import Link from "./link/Link.jsx";
import Logo from "./logo/Logo";
import { GrLanguage } from "@react-icons/all-files/gr/GrLanguage";
import { GoSignIn } from "@react-icons/all-files/go/GoSignIn";

const Header = () => {
  const [lang, setLang] = useState(false);

  return (
    <header className={style.header}>
      <div>
        <Logo />
      </div>
      <menu className={style.menu}>
        <ul className={style.ul}>
          <Link text="О проекте" to="/" />
          <Link text="Портфолио" to="/works" />
          <Link text="Обучение" to="/learning" />
          <Link text="Общение" to="/chat" />
          <GrLanguage
            onClick={() => setLang(!lang)}
            size={"25px"}
            className={style.lang}
          />
          <ul
            className={style.list}
            style={
              lang
                ? { display: "block" }
                : { display: "none", transition: "0.2s" }
            }
          >
            <li>Беларуская</li>
            <li>Русский</li>
          </ul>
          <GoSignIn className={style.reg} size={"25px"} />
        </ul>
      </menu>
    </header>
  );
};

export default Header;
